#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1005;
int n,m,p,a[N][N],dp[N],cost[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m>>p;
	memset(dp,128,sizeof(dp));
	dp[0]=0;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			cin>>a[i][j];
		}
	}
	for(int i=1;i<=n;i++)
	{
		cin>>cost[i];
	}
	for(int i=1;i<=m;i++)
	{
		for(int j=1;j<=n;j++)
		{
			int num=(j==1)?n:j-1;
			int sum=a[num][i];
			for(int k=1;k<=min(p,i);k++)
			{
				dp[i]=max(dp[i],dp[i-k]+sum-cost[num]);
				num=(num==1)?n:(num-1);
				sum+=a[num][i-k];
			}
		}
	}
	cout<<dp[m];
	return 0;
}
